#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define NUMBER_PAR_PER_BOX 100

typedef struct
{
	double x, y, z;

} THREE_VECTOR;

typedef struct
{
	double v, x, y, z;

} FOUR_VECTOR;

typedef struct
{
	int x, y, z;
	int number;
	long offset;

} nei_str;

typedef struct
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];

} box_str;

typedef struct
{
	double alpha;

} par_str;

typedef struct
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;

} dim_str;

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

__kernel void kernel_gpu_opencl(	par_str par, 
								dim_str dim,
								__global box_str* box,
								__global FOUR_VECTOR* rv,
								__global double* qv,
								__global FOUR_VECTOR* fv)
{
	int l = get_global_id(0);
	if (l >= dim.number_boxes) return;

	double alpha = par.alpha;
	double a2 = 2.0*alpha*alpha;

	long first_i = box[l].offset;
	__global FOUR_VECTOR* rA = &rv[first_i];
	__global FOUR_VECTOR* fA = &fv[first_i];

	for(int k=0; k<(1+box[l].nn); k++) {
		int pointer;
		if(k==0)
			pointer = l;
		else
			pointer = box[l].nei[k-1].number;

		long first_j = box[pointer].offset;
		__global FOUR_VECTOR* rB = &rv[first_j];
		__global double* qB = &qv[first_j];

		for(int i=0; i<NUMBER_PAR_PER_BOX; i++) {
			double fA_v = fA[i].v;
			double fA_x = fA[i].x;
			double fA_y = fA[i].y;
			double fA_z = fA[i].z;

			for(int j=0; j<NUMBER_PAR_PER_BOX; j++) {
				double r2 = rA[i].v + rB[j].v - DOT(rA[i], rB[j]);
				double u2 = a2*r2;
				double vij = exp(-u2);
				double fs = 2.0*vij;
				THREE_VECTOR d;
				d.x = rA[i].x - rB[j].x;
				d.y = rA[i].y - rB[j].y;
				d.z = rA[i].z - rB[j].z;
				double fxij = fs*d.x;
				double fyij = fs*d.y;
				double fzij = fs*d.z;

				fA_v += qB[j]*vij;
				fA_x += qB[j]*fxij;
				fA_y += qB[j]*fyij;
				fA_z += qB[j]*fzij;
			}
			fA[i].v = fA_v;
			fA[i].x = fA_x;
			fA[i].y = fA_y;
			fA[i].z = fA_z;
		}
	}
}
